#include <stdio.h>
#include <math.h>

/* Procedurally reconstruct a ray-traced scene:
   blue gradient sky, red sphere on an infinite checkerboard floor,
   with a cast shadow. No input image is read. */
int main(void){
    FILE *f = fopen("reconstructed.ppm", "wb");
    if(!f) return 1;
    fprintf(f, "P3\n2400 1800\n255\n");

    /* sphere light direction */
    const double Lx=0.49240388, Ly=0.58682409, Lz=-0.64278761;
    /* shadow ellipse (conic) coefficients */
    const double A=-5.103629746867901e-08, B=-2.048025353162011e-07,
                 C=-4.439827517326201e-07, D=0.00035297845630645307,
                 E=0.0013214051752387863, F=-0.9999990646467278;

    static char buf[1<<20];
    int bp=0;
    int y,x;
    for(y=0; y<1800; y++){
        double ys = y + 0.5;
        for(x=0; x<2400; x++){
            double xs = x + 0.5;
            int R,G,Bc;
            double dx=(xs-1200.0)/183.8, dy=(ys-993.7)/184.5;
            double rr=dx*dx+dy*dy;
            if(rr<=1.0){                       /* sphere */
                double nz=sqrt(1.0-rr);
                double d=dx*Lx - dy*Ly + nz*Lz;
                if(d<0) d=0;
                double rc=51.0+188.6*d;
                if(rc>255.0) rc=255.0;
                R=(int)(rc+0.5); G=(int)(0.196*rc+0.5); Bc=G;
            } else if(ys>=900.0){              /* floor + shadow */
                double Y=ys-900.0;
                long m=(long)floor(1.5*(xs-1200.0)/Y);
                long n=(long)floor(1349.0/Y);
                int base=((m+n)&1)?152:67;
                double cv=A*xs*xs+B*xs*ys+C*ys*ys+D*xs+E*ys+F;
                if(cv>0.0){ int v=(int)(base*0.303+0.5); R=G=Bc=v; }
                else { R=G=Bc=base; }
            } else {                           /* sky */
                double dvx=(xs-1200.0)/1200.0*(4.0/3.0);
                double dvy=(900.0-ys)/900.0;
                double diry=dvy/sqrt(dvx*dvx+dvy*dvy+1.0);
                double t=0.5*(diry+1.0);
                R=(int)(255.0*(1.0-0.5*t)+0.5);
                G=(int)(255.0*(1.0-0.3*t)+0.5);
                Bc=255;
            }
            bp+=sprintf(buf+bp, "%d %d %d\n", R,G,Bc);
            if(bp>1000000){ fwrite(buf,1,bp,f); bp=0; }
        }
    }
    if(bp) fwrite(buf,1,bp,f);
    fclose(f);
    return 0;
}
